module div_16bit(
    input clk,
    input rst,
    input sign,
    input [15:0] dividend,
    input [15:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result,
    input mux_input_1,
    input mux_input_0,
    output mux_output,
    output concat_output
);

parameter IDLE = 3'd0;
parameter SUB = 3'd1;
parameter SELECT = 3'd2;
parameter SHIFT = 3'd3;
parameter DONE = 3'd4;

reg [2:0] state;
reg [3:0] count;
reg [7:0] divisor_reg;
reg [7:0] dividend_reg;
reg [15:0] quotient_reg;
reg [7:0] remainder_reg;
reg divisor_sign, dividend_sign;

wire [8:0] sub_result;
wire [7:0] mux_output;
wire [15:0] sr_shift;
wire r;

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        state <= IDLE;
        count <= 4'b0;
        divisor_reg <= 8'b0;
        dividend_reg <= 8'b0;
        quotient_reg <= 16'b0;
        remainder_reg <= 8'b0;
        divisor_sign <= 1'b0;
        dividend_sign <= 1'b0;
    end else begin
        case (state)
            IDLE: begin
                if (opn_valid) begin
                    state <= SUB;
                    count <= 4'b0;
                    divisor_reg <= divisor;
                    dividend_reg <= dividend;
                    divisor_sign <= sign & divisor[7];
                    dividend_sign <= sign & dividend[7];
                end
            end
            SUB: begin
                if (dividend_reg == 8'b0) begin
                    state <= DONE;
                end else if (dividend_reg[7] == divisor_sign) begin
                    state <= SELECT;
                    sub_result <= dividend_reg - {1'b0, divisor_reg};
                    r <= sub_result[8];
                end else begin
                    state <= SHIFT;
                    sub_result <= 9'b0;
                    r <= 1'b0;
                end
            end
            SELECT: begin
                if (r) begin
                    state <= SHIFT;
                    quotient_reg <= {quotient_reg[14:0], 1'b0};
                end else begin
                    state <= SHIFT;
                    quotient_reg <= {quotient_reg[14:0], 1'b1};
                    dividend_reg <= {sub_result[6:0], dividend_reg[6:0]};
                end
            end
            SHIFT: begin
                if (count == 4'b1000) begin
                    state <= DONE;
                end else begin
                    state <= SUB;
                    count <= count + 4'b1;
                    dividend_reg <= {dividend_reg[6:0], 1'b0};
                end
            end
            DONE: begin
                if (res_ready) begin
                    state <= IDLE;
                    res_valid <= 1'b0;
                end else begin
                    res_valid <= 1'b1;
                    result <= {dividend_sign ^ divisor_sign, quotient_reg};
                    remainder_reg <= dividend_reg[7:0];
                end
            end
        endcase
    end
end

assign mux_output = r ? sub_result[7:0] : dividend_reg[7:0];
assign sr_shift = {divisor_reg, 8'b0};
assign mux_output = (sign && (divisor[7] ^ dividend[7])) ? ~mux_output + 1 : mux_output;
assign concat_output = {remainder_reg, dividend_reg[7:0]};

endmodule
